import xml.etree.ElementTree as ET
from io import StringIO
from lxml import etree

def process_soap_request(xml_string):
    try:
        # Parse the SOAP request with DTD validation
        parser = etree.XMLParser(dtd_validation=True)
        root = etree.parse(StringIO(xml_string), parser).getroot()

        # Extract the message body from the SOAP envelope
        soap_body = root.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')

        if soap_body is not None:
            return ET.tostring(soap_body, encoding='unicode')
        else:
            return "SOAP Body not found"

    except etree.XMLSyntaxError as e:
        # Handle XML parsing errors
        return f"XML Parsing Error: {e}"
    
    except Exception as e:
        # Catch any other exceptions and return an error message
        return f"An unexpected error occurred: {e}"

